const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

function countByType(items: any[]): Record<string, number> {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  return counts;
}

function calculateBasePremium(typeCounts: Record<string, number>): number {
  let total = 0;
  for (const [type, count] of Object.entries(typeCounts)) {
    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
      total += BLOCK_PREMIUM;
    } else {
      total += count * (BASE_PREMIUM[type] ?? 0);
    }
  }
  return total;
}

function calculateQuotePremium(items: any[]): number {
  const typeCounts = countByType(items);
  const basePremium = calculateBasePremium(typeCounts);
  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
  return Math.ceil(basePremium + firstInsurance + PROCESSING_FEE);
}

export function processScenario(scenario: any): unknown {
  const results = scenario.steps.map((step: any) => ({
    premium: calculateQuotePremium(step.items),
  }));

  return { results };
}

