  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

function countByType(items: any[]): Record<string, number> {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  return counts;
}

function calculateBasePremium(typeCounts: Record<string, number>): number {
  let total = 0;
  for (const [type, count] of Object.entries(typeCounts)) {
    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
      total += BLOCK_PREMIUM;
    } else {
      total += count * (BASE_PREMIUM[type] ?? 0);
    }
  }
  return total;
}

const CURSED_SURCHARGE_RATE = 0.5;
const ENCHANTMENT_SURCHARGE_RATE = 0.3;
const ENCHANTMENT_THRESHOLD = 5;

function calculateItemSurcharges(items: any[]): number {
  let total = 0;
  for (const item of items) {
    const base = BASE_PREMIUM[item.type] ?? 0;
    if (item.cursed) {
      total += base * CURSED_SURCHARGE_RATE;
    }
    if ((item.enchantment ?? 0) >= ENCHANTMENT_THRESHOLD) {
      total += base * ENCHANTMENT_SURCHARGE_RATE;
    }
  }
  return total;
}

const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_THRESHOLD_YEARS = 2;
const FOLLOW_UP_DISCOUNT_RATE = 0.15;

function calculateQuotePremium(items: any[], customer: any, quoteIndex: number): number {
  const typeCounts = countByType(items);
  const basePremium = calculateBasePremium(typeCounts);
  const itemSurcharges = calculateItemSurcharges(items);
  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
  const loyaltyDiscount = (customer.yearsWithMHPCO ?? 0) >= LOYALTY_THRESHOLD_YEARS
    ? basePremium * LOYALTY_DISCOUNT_RATE
    : 0;
  const followUpDiscount = quoteIndex >= 1
    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
    : 0;
  return Math.ceil(basePremium + itemSurcharges - loyaltyDiscount + firstInsurance - followUpDiscount + PROCESSING_FEE);
}

const INSURANCE_VALUE: Record<string, number> = {
  sword: 1000,
  amulet: 600,
  staff: 800,
  potion: 400,
  rune: 250,
  moonstone: 250,
};

const DEDUCTIBLE = 100;
const CAP_MULTIPLIER = 2;

function calculateInsuranceSum(items: any[]): number {
  return items.reduce(
    (sum: number, item: any) => sum + (INSURANCE_VALUE[item.type] ?? 0),
    0
  );
}

function calculateClaimResult(policy: any, incident: any): { payout: number; remainingCap: number } {
  const insuranceSum = calculateInsuranceSum(policy.items);
  const cap = insuranceSum * CAP_MULTIPLIER;
  let totalPayout = 0;
  for (const damage of incident.damages) {
    totalPayout += damage.amount - DEDUCTIBLE;
  }
  totalPayout = Math.floor(totalPayout);
  const remainingCap = cap - totalPayout;
  return { payout: totalPayout, remainingCap };
}

export function processScenario(scenario: any): unknown {
  const policies: any[] = [];
  const results: any[] = [];
  let quoteIndex = 0;

  for (const step of scenario.steps) {
    if (step.op === "claim") {
      const policy = policies[step.policy];
      results.push(calculateClaimResult(policy, step.incident));
    } else {
      policies.push({ items: step.items });
      results.push({
        premium: calculateQuotePremium(step.items, scenario.customer, quoteIndex),
      });
      quoteIndex++;
    }
  }

  return { results };
}

